import http from "../01_axios"
import {
  apiDeleteNotifyForUser,
  apiGetListNotify,
  apiGetNewNotification,
  apiGetRequestCounter,
  apiMarkAllAsRead,
} from "./urls"

const getListNotify = params => http.get(apiGetListNotify, { params })

/**
 * Đánh dấu MỘT thông báo là đã đọc bằng cách truyền ID vào query param.
 * @param {string} notifyId - ID của thông báo cần đánh dấu.
 */
const markOneAsRead = notifyId => {
  // Axios PATCH signature: patch(url, data, config)
  // Data là null vì backend không cần body.
  // ID được truyền vào params để trở thành query string.
  return http.patch(apiMarkAllAsRead, null, {
    params: {
      NotifyId: notifyId,
    },
  })
}

/**
 * Đánh dấu TẤT CẢ thông báo là đã đọc bằng cách gọi API không có tham số.
 */
const markAllAsRead = () => {
  // Gửi request PATCH không có body và không có params.
  return http.patch(apiMarkAllAsRead)
}
const deleteNotifyForUser = data => http.patch(apiDeleteNotifyForUser, data)
const getNewNotify = () => http.get(apiGetNewNotification)
const getRequestCounter = () => http.get(apiGetRequestCounter)

const Notify = {
  getListNotify,
  getNewNotify,
  markOneAsRead,
  markAllAsRead, // Hàm đã được sửa lại
  deleteNotifyForUser,
  getRequestCounter,
}

export default Notify
